import React from 'react';
import { Card, CardContent, Box, Typography, Stack, IconButton } from '@mui/material';
import { PlayArrow, Pause, Shuffle, Repeat, VolumeUp } from '@mui/icons-material';
import response from './response.json';

interface CurrentTrack {
  title: string;
  artist: string;
  album: string;
  duration: string;
  elapsed: string;
}

interface PlaybackControls {
  isPlaying: boolean;
  volume: number;
  shuffle: boolean;
  repeat: string;
}

interface UpNextTrack {
  title: string;
  artist: string;
  duration: string;
}

interface MusicPlayerData {
  currentTrack: CurrentTrack;
  playbackControls: PlaybackControls;
  upNext: UpNextTrack[];
}

export default function Widget() {
  const musicData = response.data as MusicPlayerData;
  const { currentTrack, playbackControls, upNext } = musicData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1C1C1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF4081' }}>
              Now Playing
            </Typography>
            <Typography variant="body1" sx={{ mt: 0.5 }}>
              {currentTrack.title} - {currentTrack.artist}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              {currentTrack.album}
            </Typography>
            <Typography variant="caption" color="text.secondary" sx={{ mt: 0.5 }}>
              {currentTrack.elapsed} / {currentTrack.duration}
            </Typography>
          </Box>

          <Stack direction="row" spacing={1} alignItems="center">
            <IconButton sx={{ color: playbackControls.isPlaying ? '#FF4081' : '#FFFFFF' }}>
              {playbackControls.isPlaying ? <Pause /> : <PlayArrow />}
            </IconButton>
            <IconButton sx={{ color: playbackControls.shuffle ? '#FF4081' : '#FFFFFF' }}>
              <Shuffle />
            </IconButton>
            <IconButton sx={{ color: playbackControls.repeat === 'all' ? '#FF4081' : '#FFFFFF' }}>
              <Repeat />
            </IconButton>
            <VolumeUp sx={{ color: '#FFFFFF', mr: 1 }} />
            <Typography variant="body2">{playbackControls.volume}%</Typography>
          </Stack>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Up Next
            </Typography>
            <Stack spacing={0.5}>
              {upNext.map((track, index) => (
                <Typography key={index} variant="body2">
                  {track.title} - {track.artist} ({track.duration})
                </Typography>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
